function Calculator() {
  const [display, setDisplay] = React.useState('0');
  const [prev, setPrev] = React.useState(null);
  const [op, setOp] = React.useState(null);
  const [newNum, setNewNum] = React.useState(true);

  const press = (val)=>{
    if(['+','-','×','÷'].includes(val)){
      setPrev(parseFloat(display));setOp(val);setNewNum(true);return;
    }
    if(val==='='){
      if(prev===null||!op)return;
      const cur = parseFloat(display);
      let res = 0;
      if(op==='+')res=prev+cur;
      if(op==='-')res=prev-cur;
      if(op==='×')res=prev*cur;
      if(op==='÷')res=prev/cur;
      setDisplay(String(Math.round(res*1e8)/1e8));
      setPrev(null);setOp(null);setNewNum(true);return;
    }
    if(val==='C'){setDisplay('0');setPrev(null);setOp(null);setNewNum(true);return;}
    if(val==='←'){setDisplay(d=>d.length>1?d.slice(0,-1):'0');return;}
    if(val==='.'&&display.includes('.'))return;
    if(newNum){setDisplay(val==='.'?'0.':val);setNewNum(false);}
    else{setDisplay(d=>d==='0'&&val!=='.'?val:d+val);}
  };

  const keys = ['C','←','÷','×','7','8','9','-','4','5','6','+','1','2','3','=','0','.'];

  return (
    <div style={{padding:12,fontFamily:'system-ui',display:'flex',flexDirection:'column',alignItems:'center',height:'100%'}}>
      <div style={{width:220,textAlign:'right',padding:'12px 16px',background:'#1a1a1a',color:'#fff',borderRadius:10,fontSize:28,fontWeight:200,fontVariantNumeric:'tabular-nums',marginBottom:12,overflow:'hidden'}}>
        {display}
      </div>
      <div style={{display:'grid',gridTemplateColumns:'repeat(4,50px)',gap:6}}>
        {keys.map(k=> (
          <button key={k} onClick={()=>press(k)}
            style={{
              width:50,height:50,fontSize:18,borderRadius:10,border:'none',cursor:'pointer',
              background:['C','←'].includes(k)?'#FF3B30':['÷','×','-','+','='].includes(k)?'#FF9500':'#f5f5f5',
              color:['C','←','÷','×','-','+','='].includes(k)?'#fff':'#000',
              gridColumn:k==='0'?'span 2':undefined
            }}>
            {k}
          </button>
        ))}
      </div>
    </div>
  );
}
render(<Calculator/>);
